using UnityEngine;

[RequireComponent(typeof(BoxCollider2D))]
public class CameraAreaBounds : MonoBehaviour
{
    [Header("Área (opcional)")]
    [Tooltip("Se definido, ao entrar aqui actualiza WorldState.CurrentArea e marca a área como visitada (PlayerProgress).")]
    [SerializeField] private AreaData area;

    private BoxCollider2D bounds;

    private void Awake()
    {
        bounds = GetComponent<BoxCollider2D>();
        bounds.isTrigger = true;
    }

    private void ApplyIfPlayer(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        if (CameraManager.Instance != null)
            CameraManager.Instance.SetBaseBounds(bounds);

        if (area != null)
        {
            bool areaChanged = WorldState.Instance != null && WorldState.Instance.SetCurrentArea(area);
            PlayerProgress.Instance?.MarkVisited(area);

            // Autosave ao entrar numa área diferente (cobre também "entrar/sair
            // de uma cidade", já que isso é sempre uma mudança de área).
            if (areaChanged) SaveManager.Instance?.SaveAutosave();
        }
    }

    private void OnTriggerEnter2D(Collider2D other) => ApplyIfPlayer(other);

    private void OnTriggerStay2D(Collider2D other) => ApplyIfPlayer(other);
}
